    m_qualityMetrics = assessCodeQuality(m_projectPath);
    
    if (onNotification) {
        onNotification("Quality", std::format(
            "Quality Score: {:.2f}, Maintainability: {:.2f}, Performance: {:.2f}, Security: {:.2f}",
            m_qualityMetrics.codeQualityScore,
