        {"issues_count", m_qualityMetrics.issues.size()}
    };
}

// Real quality calculation (not simulation)
float AutonomousIntelligenceOrchestrator::calculateQualityScore(const std::string& code) {
    float score = 1.0f;
    
    // Deduct for complexity
    int complexity = 0;
    for (char c : code) {
        if (c == '{' || c == '}' || c == '(' || c == ')') complexity++;
    }
    score -= (complexity / 1000.0f);
    
    // Deduct for issues
    auto issues = scanForIssues(code);
    score -= (issues.size() * 0.1f);
    
    return std::max(0.0f, score);
}

float AutonomousIntelligenceOrchestrator::calculateMaintainabilityScore(const std::string& code) {
    // Real maintainability calculation
    float score = 1.0f;
    
    // Check for comments
    size_t commentCount = 0;
    size_t pos = 0;
    while ((pos = code.find("//", pos)) != std::string::npos) {
        commentCount++;
        pos += 2;
    }
    
    // Comment ratio
    float commentRatio = static_cast<float>(commentCount) / (code.length() / 100);
    if (commentRatio < 0.1f) score -= 0.3f; // Not enough comments
    
    // Function length
    if (code.find("{\n") != std::string::npos) {
        // Count lines per function
        size_t functionCount = std::count(code.begin(), code.end(), '{');
        size_t totalLines = std::count(code.begin(), code.end(), '\n');
        float avgFunctionLength = static_cast<float>(totalLines) / functionCount;
        
        if (avgFunctionLength > 50) score -= 0.2f; // Functions too long
    }
    
    return std::max(0.0f, score);
}

float AutonomousIntelligenceOrchestrator::calculatePerformanceScore(const std::string& code) {
    float score = 1.0f;
    
    // Check for inefficient patterns
    if (code.find("for (int i = 0; i < vec.size(); i++)") != std::string::npos) {
        score -= 0.2f; // Inefficient loop
    }
    
    if (code.find("std::endl") != std::string::npos) {
        score -= 0.1f; // Unnecessary flush
    }
    
    return std::max(0.0f, score);
}

float AutonomousIntelligenceOrchestrator::calculateSecurityScore(const std::string& code) {
    float score = 1.0f;
    
    // Check for security vulnerabilities
    if (code.find("strcpy(") != std::string::npos) score -= 0.3f;
    if (code.find("sprintf(") != std::string::npos) score -= 0.2f;
    if (code.find("gets(") != std::string::npos) score -= 0.5f;
    if (code.find("system(") != std::string::npos) score -= 0.3f;
    
    return std::max(0.0f, score);
}

std::vector<std::string> AutonomousIntelligenceOrchestrator::detectSecurityVulnerabilities(const std::string& code) {
    std::vector<std::string> vulnerabilities;
    
    if (code.find("strcpy(") != std::string::npos) {
        vulnerabilities.push_back("Buffer overflow vulnerability: strcpy");
    }
    
    if (code.find("gets(") != std::string::npos) {
        vulnerabilities.push_back("Critical vulnerability: gets");
    }
    
    if (code.find("system(") != std::string::npos) {
        vulnerabilities.push_back("Command injection vulnerability: system");
    }
    
    if (code.find("scanf(") != std::string::npos && code.find("%s") != std::string::npos) {
        vulnerabilities.push_back("Buffer overflow vulnerability: scanf with %s");
    }
    
    return vulnerabilities;
}

