class FileReadTool : public ITool {
public:
    std::string getName() const override { return "file_read"; }
    std::string getDescription() const override { return "Read contents of a file"; }
    std::vector<std::string> getParameters() const override { return {"path"}; }
    std::string getCategory() const override { return "file"; }
    
    std::expected<ToolResult, ToolError> execute(
        const std::unordered_map<std::string, std::string>& params
    ) override {
        if (params.find("path") == params.end()) {
            return std::unexpected(ToolError::InvalidParameters);
        }
        
        std::string path = params.at("path");
        std::ifstream file(path);
        
        if (!file) {
            ToolResult result;
            result.success = false;
            result.output = "Failed to open file: " + path;
            result.exitCode = 1;
            return result;
        }
        
        std::string content((std::istreambuf_iterator<char>(file)),
                           std::istreambuf_iterator<char>());
        
        ToolResult result;
        result.success = true;
        result.output = content;
        result.exitCode = 0;
        return result;
    }
