class CompileTool : public ITool {
public:
    std::string getName() const override { return "compile"; }
    std::string getDescription() const override { return "Compile source code"; }
    std::vector<std::string> getParameters() const override { return {"source", "output", "flags"}; }
    std::string getCategory() const override { return "build"; }
    
