    ) override {
        std::string source = params.at("source");
        std::string output = params.at("output");
        std::string flags = params.count("flags") ? params.at("flags") : "";
        
        // Real compilation using MSVC
        std::string command = std::format("cl {} /Fe:{} {}", flags, output, source);
        
        ToolResult result;
        result.duration = std::chrono::milliseconds(0);
        
        auto start = std::chrono::steady_clock::now();
        int exitCode = std::system(command.c_str());
        auto end = std::chrono::steady_clock::now();
        
        result.duration = std::chrono::duration_cast<std::chrono::milliseconds>(end - start);
        result.exitCode = exitCode;
        
        if (exitCode == 0) {
            result.success = true;
            result.output = "Compilation successful: " + output;
        } else {
            result.success = false;
            result.output = "Compilation failed for: " + source;
        }
        
        return result;
    }
};

class DebugTool : public ITool {
public:
    std::string getName() const override { return "debug"; }
    std::string getDescription() const override { return "Debug executable and capture output"; }
    std::vector<std::string> getParameters() const override { return {"executable", "args"}; }
    std::string getCategory() const override { return "debug"; }
    
    std::expected<ToolResult, ToolError> execute(
        const std::unordered_map<std::string, std::string>& params
    ) override {
        std::string executable = params.at("executable");
        std::string args = params.count("args") ? params.at("args") : "";
        
        // Real debugging using Win32 Debug API
        STARTUPINFOA si = {sizeof(si)};
        PROCESS_INFORMATION pi;
        
        std::string commandLine = executable + " " + args;
        
        if (!CreateProcessA(nullptr, const_cast<char*>(commandLine.c_str()), 
                           nullptr, nullptr, FALSE, 
                           DEBUG_PROCESS, nullptr, nullptr, &si, &pi)) {
            ToolResult result;
            result.success = false;
            result.output = "Failed to start process: " + executable;
            result.exitCode = GetLastError();
            return result;
        }
        
        // Debug loop
        DEBUG_EVENT debugEvent;
        std::string debugOutput;
        
        while (WaitForDebugEvent(&debugEvent, 100)) {
            switch (debugEvent.dwDebugEventCode) {
                case EXCEPTION_DEBUG_EVENT:
                    debugOutput += "Exception occurred\n";
                    break;
                    
                case OUTPUT_DEBUG_STRING_EVENT:
                    debugOutput += "Debug output: " + 
                        std::string(debugEvent.u.DebugString.lpDebugStringData) + "\n";
                    break;
                    
                case EXIT_PROCESS_DEBUG_EVENT:
                    debugOutput += "Process exited with code: " + 
                        std::to_string(debugEvent.u.ExitProcess.dwExitCode) + "\n";
                    break;
            }
            
            ContinueDebugEvent(debugEvent.dwProcessId, debugEvent.dwThreadId, DBG_CONTINUE);
        }
        
        CloseHandle(pi.hProcess);
        CloseHandle(pi.hThread);
        
        ToolResult result;
        result.success = true;
        result.output = debugOutput;
        result.exitCode = 0;
        return result;
    }
};

