namespace RawrXD {

MultiTabEditor::MultiTabEditor() {
    // Create default tab
    auto defaultTab = std::make_unique<EditorTab>();
    defaultTab->title = "Untitled";
    defaultTab->isModified = false;
    defaultTab->isActive = true;
    defaultTab->buffer = std::make_unique<EditorBuffer>();
    defaultTab->highlighter = std::make_unique<SyntaxHighlighter>();
    defaultTab->completionProvider = std::make_unique<CompletionProvider>();
    
    m_tabs.push_back(std::move(*defaultTab));
    m_activeTabIndex = 0;
}

Result<int> MultiTabEditor::openFile(const std::string& filePath) {
    std::lock_guard lock(m_mutex);
    
    // Check if file already open
    for (size_t i = 0; i < m_tabs.size(); ++i) {
        if (m_tabs[i].filePath == filePath) {
            // Switch to existing tab
            auto switchResult = switchToTab(i);
            if (!switchResult) {
                return switchResult.error();
            }
            return static_cast<int>(i);
        }
    }
    
    // Create new tab
    EditorTab newTab;
    newTab.filePath = filePath;
    newTab.title = fs::path(filePath).filename().string();
    newTab.isModified = false;
    newTab.isActive = false;
    
    // Read file content
    std::ifstream file(filePath);
    if (!file) {
        return std::unexpected(EditorError::FileNotFound);
    }
    
    std::string content((std::istreambuf_iterator<char>(file)),
                       std::istreambuf_iterator<char>());
    
    newTab.buffer = std::make_unique<EditorBuffer>();
    newTab.buffer->setText(content);
    
    // Initialize highlighter and completion
    newTab.highlighter = std::make_unique<SyntaxHighlighter>();
    newTab.highlighter->setLanguage(detectLanguage(filePath));
    
    newTab.completionProvider = std::make_unique<CompletionProvider>();
    newTab.completionProvider->setLSPClient(m_lspClient);
    
    m_tabs.push_back(std::move(newTab));
    int newTabIndex = static_cast<int>(m_tabs.size() - 1);
    
    // Switch to new tab
    auto switchResult = switchToTab(newTabIndex);
    if (!switchResult) {
        return switchResult.error();
    }
    
    // Apply syntax highlighting
    applySyntaxHighlighting(newTabIndex);
    
    if (onTabEvent) {
        onTabEvent(newTabIndex, "opened");
    }
    
    return newTabIndex;
}

Result<void> MultiTabEditor::saveTab(int tabIndex) {
    auto tabResult = getTab(tabIndex);
    if (!tabResult) {
        return tabResult.error();
    }
    
    EditorTab* tab = tabResult.value();
    
    if (tab->filePath.empty()) {
        // New file, need save as
        return std::unexpected(EditorError::NoFilePath);
    }
    
    std::ofstream file(tab->filePath);
    if (!file) {
        return std::unexpected(EditorError::FileWriteFailed);
    }
    
    file << tab->buffer->getText();
    tab->isModified = false;
    
    if (onTabEvent) {
        onTabEvent(tabIndex, "saved");
    }
    
    return {};
}

Result<std::vector<std::string>> MultiTabEditor::getCompletions(int tabIndex, int line, int column) {
    auto tabResult = getTab(tabIndex);
    if (!tabResult) {
        return tabResult.error();
    }
    
    EditorTab* tab = tabResult.value();
    
    // Get context from buffer
    std::string context = tab->buffer->getContextAround(line, column);
    
    // Real completion using LSP
    if (tab->completionProvider) {
        return tab->completionProvider->getCompletions(tab->filePath, line, column, context);
    }
    
    // Fallback to basic completions
    return std::vector<std::string>{"if", "for", "while", "class", "struct"};
}

Result<void> MultiTabEditor::applySyntaxHighlighting(int tabIndex) {
    auto tabResult = getTab(tabIndex);
    if (!tabResult) {
        return tabResult.error();
    }
    
    EditorTab* tab = tabResult.value();
    
    if (!tab->highlighter) {
        return {};
    }
    
    // Real syntax highlighting
    std::string text = tab->buffer->getText();
    auto tokens = tab->highlighter->tokenize(text);
    
    for (const auto& token : tokens) {
        // Apply highlighting based on token type
        switch (token.type) {
            case TokenType::Keyword:
                tab->buffer->setStyle(token.start, token.length, Style::Keyword);
                break;
            case TokenType::Identifier:
                tab->buffer->setStyle(token.start, token.length, Style::Identifier);
                break;
            case TokenType::String:
                tab->buffer->setStyle(token.start, token.length, Style::String);
                break;
            case TokenType::Comment:
                tab->buffer->setStyle(token.start, token.length, Style::Comment);
                break;
            case TokenType::Number:
                tab->buffer->setStyle(token.start, token.length, Style::Number);
                break;
            default:
                break;
        }
    }
    
    return {};
}

