```cpp
#include "ChatInterface.h"
#include <fstream>
#include <sstream>

namespace RawrXD {

ChatInterface::ChatInterface() {
    // Add system message
    ChatMessage systemMessage;
    systemMessage.id = generateMessageId();
    systemMessage.role = "system";
    systemMessage.content = "RawrXD Agentic IDE Assistant. Type 'help' for commands.";
    systemMessage.timestamp = std::chrono::system_clock::now();
    
    m_messages.push_back(systemMessage);
}

Result<void> ChatInterface::sendMessage(const std::string& content) {
    return sendMessage(content, "user");
}

Result<void> ChatInterface::sendMessage(const std::string& content, const std::string& role) {
    // Create message
    ChatMessage message;
    message.id = generateMessageId();
    message.role = role;
    message.content = content;
    message.timestamp = std::chrono::system_clock::now();
    
    // Add to history
    auto addResult = addMessageToHistory(message);
    if (!addResult) {
        return addResult.error();
    }
    
    // Trigger agent processing
    if (role == "user") {
        auto processResult = processMessageWithAgents(content);
        if (!processResult) {
            return processResult.error();
        }
        
        // Add assistant response
        ChatMessage response;
        response.id = generateMessageId();
        response.role = "assistant";
        response.content = processResult.value();
        response.timestamp = std::chrono::system_clock::now();
        
        addResult = addMessageToHistory(response);
        if (!addResult) {
            return addResult.error();
        }
        
        // Trigger event
        if (onMessageReceived) {
            onMessageReceived(response);
        }
    }
    
    return {};
}

Result<std::string> ChatInterface::processMessageWithAgents(const std::string& content) {
    std::string response;
    
    // Route to appropriate agent based on content
    if (content.find("debug") != std::string::npos && m_zeroDayAgent) {
        // Use zero-day agent for debugging
        auto result = m_zeroDayAgent->analyze(content);
        if (result) {
            response = result.value();
        }
    } else if (content.find("plan") != std::string::npos && m_planOrchestrator) {
        // Use plan orchestrator for planning
        auto plan = m_planOrchestrator->createPlan(content);
        response = "Plan created: " + plan;
    } else if (m_agenticEngine) {
        // Use general agentic engine
        auto result = m_agenticEngine->process(content);
        if (result) {
            response = result.value();
        }
    } else {
        response = "No agents available to process: " + content;
    }
    
    return response;
}

Result<void> ChatInterface::streamMessage(
    const std::string& content,
    std::function<void(const std::string& token)> onToken
) {
    if (m_isStreaming.exchange(true)) {
        return std::unexpected(ChatError::AlreadyStreaming);
    }
    
    m_stopStreaming = false;
    
    // Start streaming thread
    m_streamingThread = std::thread(&ChatInterface::streamingLoop, this, content, onToken);
    
    return {};
}

void ChatInterface::streamingLoop(
    const std::string& content,
    std::function<void(const std::string& token)> onToken
) {
    // Real streaming with token-by-token generation
    auto result = m_agenticEngine->generateStreaming(content,
        [this, onToken](const std::string& token) {
            if (m_stopStreaming.load()) {
                return false; // Stop
            }
            
            if (onToken) {
                onToken(token);
            }
            
            // Add to partial message
            std::lock_guard lock(m_mutex);
            if (!m_messages.empty() && m_messages.back().role == "assistant") {
                m_messages.back().content += token;
            }
            
            return true; // Continue
        }
    );
    
    m_isStreaming = false;
    
    if (!result && onError) {
        onError(result.error());
    }
}

Result<void> ChatInterface::saveConversation(const std::string& conversationId) {
    std::lock_guard lock(m_mutex);
    
    json conversation = {
        {"id", conversationId},
        {"messages", json::array()},
        {"timestamp", std::chrono::system_clock::to_time_t(std::chrono::system_clock::now())}
    };
    
    for (const auto& msg : m_messages) {
        conversation["messages"].push_back({
            {"id", msg.id},
            {"role", msg.role},
            {"content", msg.content},
            {"timestamp", std::chrono::system_clock::to_time_t(msg.timestamp)}
        });
    }
    
    std::string filename = std::format("conversations/{}.json", conversationId);
    std::ofstream file(filename);
    
    if (!file) {
        return std::unexpected(ChatError::FileWriteFailed);
    }
    
    file << conversation.dump(2);
    return {};
}

