std::expected<ExecutionPlan, PlanError> PlanOrchestrator::createPlan(const std::string& goal) {
    if (goal.empty()) {
        return std::unexpected(PlanError::InvalidGoal);
    }
    
    ExecutionPlan plan;
    plan.id = generatePlanId();
    plan.goal = goal;
    plan.createdAt = std::chrono::steady_clock::now();
    
    // Real plan generation using inference engine
    auto stepsResult = generateSteps(goal);
    if (!stepsResult) {
        return std::unexpected(stepsResult.error());
    }
    
    plan.steps = stepsResult.value();
    
    // Save plan
    auto saveResult = savePlan(plan);
    if (!saveResult) {
        return std::unexpected(saveResult.error());
    }
    
    return plan;
}

std::expected<std::vector<PlanStep>, PlanError> PlanOrchestrator::generateSteps(
    const std::string& goal
) {
    std::vector<PlanStep> steps;
    
    // Use inference engine to break down goal into steps
    if (!m_inferenceEngine) {
        return std::unexpected(PlanError::PlanGenerationFailed);
    }
    
    std::string prompt = std::format(
        "Break down the following goal into actionable steps. "
        "Each step should specify a tool and parameters.\n\n"
        "Goal: {}\n\n"
        "Steps:\n1. ", goal
    );
    
    auto inferenceResult = m_inferenceEngine->generate(prompt, 0.7f, 0.9f, 512);
    if (!inferenceResult) {
        return std::unexpected(PlanError::PlanGenerationFailed);
    }
    
    // Parse generated steps
    std::string generatedText = inferenceResult->text;
    std::istringstream stream(generatedText);
    std::string line;
    int stepNumber = 1;
    
    while (std::getline(stream, line)) {
        if (line.find(std::to_string(stepNumber) + ".") == 0) {
            PlanStep step;
            step.id = std::format("step_{}", stepNumber);
            step.description = line.substr(line.find(".") + 2);
            
            // Extract tool and parameters (simplified)
            if (line.find("compile") != std::string::npos) {
                step.tool = "compile";
            } else if (line.find("read") != std::string::npos) {
                step.tool = "file_read";
            } else if (line.find("write") != std::string::npos) {
                step.tool = "file_write";
            } else {
                step.tool = "generic";
            }
            
            steps.push_back(step);
            stepNumber++;
        }
    }
    
    return steps;
}

std::expected<ExecutionPlan, PlanError> PlanOrchestrator::executePlan(ExecutionPlan& plan) {
    plan.isCompleted = false;
    
    for (auto& step : plan.steps) {
        if (!m_inferenceEngine) {
            return std::unexpected(PlanError::ExecutionFailed);
        }
        
        auto stepResult = executeStep(step);
        if (!stepResult) {
            // Rollback
            rollbackStep(step);
            return std::unexpected(stepResult.error());
        }
    }
    
    plan.isCompleted = true;
    plan.completedAt = std::chrono::steady_clock::now();
    plan.successRate = 1.0f;
    
    // Save completed plan
    savePlan(plan);
    
    return plan;
}

std::expected<void, PlanError> PlanOrchestrator::executeStep(PlanStep& step) {
    // Validate step
    auto validationResult = validateStep(step);
    if (!validationResult) {
        return std::unexpected(validationResult.error());
    }
    
    if (!validationResult.value()) {
        step.isCompleted = true;
        step.result = "Skipped (validation failed)";
        return {};
    }
    
    // Execute using tool registry
    if (!m_modelRouter) {
        return std::unexpected(PlanError::ExecutionFailed);
    }
    
    auto toolRegistry = m_modelRouter->getToolRegistry();
    if (!toolRegistry) {
        return std::unexpected(PlanError::ExecutionFailed);
    }
    
    auto toolResult = toolRegistry->executeTool(step.tool, step.parameters);
    if (!toolResult) {
        step.isCompleted = false;
        step.result = "Failed: " + std::string(toolResult.error());
        return std::unexpected(PlanError::StepFailed);
    }
    
    step.isCompleted = true;
    step.result = toolResult->output;
    step.duration = toolResult->duration;
    
    return {};
}

std::expected<void, PlanError> PlanOrchestrator::savePlan(const ExecutionPlan& plan) {
    std::string filename = m_plansDirectory + plan.id + ".json";
    std::ofstream file(filename);
    
    if (!file) {
        return std::unexpected(PlanError::ExecutionFailed);
    }
    
    json planJson = {
        {"id", plan.id},
        {"goal", plan.goal},
        {"steps", json::array()},
        {"created_at", std::chrono::system_clock::to_time_t(plan.createdAt)},
        {"is_completed", plan.isCompleted},
        {"success_rate", plan.successRate}
    };
    
    for (const auto& step : plan.steps) {
        planJson["steps"].push_back({
            {"id", step.id},
            {"description", step.description},
            {"tool", step.tool},
            {"parameters", step.parameters},
            {"is_completed", step.isCompleted},
            {"result", step.result},
            {"duration_ms", step.duration.count()}
        });
    }
    
    if (plan.isCompleted) {
        planJson["completed_at"] = std::chrono::system_clock::to_time_t(plan.completedAt);
    }
    
    file << planJson.dump(2);
    return {};
}

