void AutonomousModelManager::startAutonomousManagement() {
    if (m_autonomousManagementRunning.exchange(true)) {
        return;
    }
    
    m_managementThread = std::thread(&AutonomousModelManager::autonomousManagementLoop, this);
}

void AutonomousModelManager::stopAutonomousManagement() {
    if (!m_autonomousManagementRunning.exchange(false)) {
        return;
    }
    
    if (m_managementThread.joinable()) {
        m_managementThread.join();
    }
}

