    // Warmup
    for (int i = 0; i < 5; ++i) {
        m_ide->getInferenceEngine()->generate("Hello", 0.7f, 0.9f, 10);
    }
    
    // Measure latency
    auto latencyStart = std::chrono::steady_clock::now();
    auto inferenceResult = m_ide->getInferenceEngine()->generate(
