        0.7f, 0.9f, 100
    );
    auto latencyEnd = std::chrono::steady_clock::now();
    
    if (inferenceResult) {
        result.inferenceLatency = std::chrono::duration_cast<std::chrono::milliseconds>(
            latencyEnd - latencyStart).count();
        
        // Measure token generation rate
        result.tokenGenerationRate = static_cast<float>(inferenceResult->tokensGenerated) / 
                                     (result.inferenceLatency / 1000.0f);
        
        // Measure memory efficiency
        result.memoryEfficiency = 1.0f - (inferenceResult->memoryUsageMB / 8192.0f);
    }
    
    return result;
